import InstagramIcon from '@mui/icons-material/Instagram';
import LocalMallRoundedIcon from '@mui/icons-material/LocalMallRounded';
import FavoriteRoundedIcon from '@mui/icons-material/FavoriteRounded';
import { AppBar, Badge, IconButton, Toolbar, Typography, Box, Container } from "@mui/material";

function Header({ handleCart, orderLen, handleWish, wishLen }) {
    return (
        <AppBar 
            position='sticky' 
            sx={{ 
                top: 0,
                zIndex: 1100,
            }}
        >
            <Container maxWidth="xl">
                <Toolbar disableGutters sx={{ height: '80px' }}>
                    <Typography
                        variant="h6"
                        component="a"
                        href='/'
                        sx={{
                            flexGrow: 1,
                            fontFamily: '"Plus Jakarta Sans", "Inter", sans-serif',
                            fontWeight: 800,
                            letterSpacing: '-0.02em',
                            color: 'white',
                            textDecoration: 'none',
                            textTransform: 'uppercase',
                            fontSize: '1.25rem',
                        }}
                    >
                        Wear <Box component="span" sx={{ color: 'primary.main' }}>&</Box> Enjoy
                    </Typography>

                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        <IconButton
                            color="inherit"
                            href="https://instagram.com/wear_and_enjoy_it?igshid=ZDdkNTZiNTM="
                            sx={{ 
                                transition: 'transform 0.2s',
                                '&:hover': { transform: 'translateY(-2px)', color: 'primary.main' }
                            }}
                        >
                            <InstagramIcon />
                        </IconButton>

                        <IconButton
                            color="inherit"
                            onClick={handleWish}
                            sx={{ 
                                transition: 'transform 0.2s',
                                '&:hover': { transform: 'translateY(-2px)', color: 'primary.main' }
                            }}
                        >
                            <Badge
                                badgeContent={wishLen}
                                color="primary"
                                sx={{ '& .MuiBadge-badge': { fontWeight: 700 } }}
                            >
                                <FavoriteRoundedIcon />
                            </Badge>
                        </IconButton>

                        <IconButton
                            color="inherit"
                            onClick={handleCart}
                            sx={{ 
                                transition: 'transform 0.2s',
                                '&:hover': { transform: 'translateY(-2px)', color: 'primary.main' }
                            }}
                        >
                            <Badge
                                badgeContent={orderLen}
                                color="primary"
                                sx={{ '& .MuiBadge-badge': { fontWeight: 700 } }}
                            >
                                <LocalMallRoundedIcon />
                            </Badge>
                        </IconButton>
                    </Box>
                </Toolbar>
            </Container>
        </AppBar>
    )
}

export default Header;
